# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit
import AppKit

class URLHandler {
    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else { return false }
        
        if let token = components.queryItems?.first(where: { $0.name == "token" })?.value {
            // Navigate to the password reset screen with the token
            let navigationController = window.rootViewController as? UINavigationController
            let destinationVC = PasswordResetViewController(token: token)
            navigationController?.pushViewController(destinationVC, animated: true)
        }
        
        return false
    }
}

extension UIApplication {
    var urlHandler: URLHandler { get { (window?.rootViewController as? URLHandler) ?? URLHandler() } }
}

class AppDelegate: UIResponder, UIApplicationDelegate {
    func application(_ app: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIApplicationRestorableState]?) -> Void) -> Bool {
        if let url = userActivity.url {
            return urlHandler.application(app, open: url, options: [:])
        }
        
        return false
    }
}

